#include "controller.h"

static void controller_set_safe_state(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static uint32_t controller_elapsed_ms(uint32_t now_ms, uint32_t then_ms)
{
    return now_ms - then_ms;
}

static bool controller_pressure_is_stale(const controller_t *controller, uint32_t now_ms)
{
    return controller->has_valid_pressure &&
        (controller_elapsed_ms(now_ms, controller->last_pressure_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);
}

static bool controller_door_is_stale(const controller_t *controller, uint32_t now_ms)
{
    return controller->has_valid_door &&
        (controller_elapsed_ms(now_ms, controller->last_door_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);
}

static controller_output_t controller_make_output(const controller_t *controller,
                                                  bool changed,
                                                  bool timed_out)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = CONTROLLER_STATE_SAFE_VENT_NAME,
        .changed = changed,
        .timed_out = timed_out,
    };

    if (controller == NULL) {
        return output;
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    return output;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_state(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;
    bool timed_out = false;
    bool force_safe = false;

    if (controller == NULL) {
        return controller_make_output(NULL, false, false);
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        timed_out = true;
        force_safe = true;
        break;

    case CONTROLLER_INPUT_INVALID_PRESSURE:
        controller->has_valid_pressure = false;
        force_safe = true;
        break;

    case CONTROLLER_INPUT_INVALID_DOOR:
        controller->has_valid_door = false;
        force_safe = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (!force_safe) {
        if (controller_pressure_is_stale(controller, input.now_ms) ||
            controller_door_is_stale(controller, input.now_ms)) {
            timed_out = true;
            force_safe = true;
        }
    }

    if (force_safe || !controller->has_valid_pressure || !controller->has_valid_door || !controller->door_closed) {
        controller_set_safe_state(controller);
    } else if (controller->last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
        controller->compressor_on = true;
        controller->vent_open = false;
        controller->state = CONTROLLER_STATE_PRESSURIZING;
    } else if (controller->last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_RELIEVING;
    } else {
        if (controller->compressor_on && controller->vent_open) {
            controller_set_safe_state(controller);
        }
        controller->state = CONTROLLER_STATE_HOLDING;
    }

    return controller_make_output(
        controller,
        (controller->compressor_on != previous_compressor_on) ||
            (controller->vent_open != previous_vent_open) ||
            (controller->state != previous_state),
        timed_out
    );
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_VENT:
        return CONTROLLER_STATE_SAFE_VENT_NAME;
    case CONTROLLER_STATE_PRESSURIZING:
        return CONTROLLER_STATE_PRESSURIZING_NAME;
    case CONTROLLER_STATE_HOLDING:
        return CONTROLLER_STATE_HOLDING_NAME;
    case CONTROLLER_STATE_RELIEVING:
        return CONTROLLER_STATE_RELIEVING_NAME;
    default:
        return CONTROLLER_STATE_SAFE_VENT_NAME;
    }
}

